class Solution {
    public int nthUglyNumber(int n) {
        int[] ugly = new int[n];
        ugly[0] = 1;
        int i = 0, j = 0, k = 0;
        for (int index = 1; index < n; index++) {
            ugly[index] = Math.min(Math.min(ugly[i] * 2, ugly[j] * 3), ugly[k] * 5);
            if (ugly[index] == ugly[i] * 2) i++;
            if (ugly[index] == ugly[j] * 3) j++;
            if (ugly[index] == ugly[k] * 5) k++;
        }
        return ugly[n - 1];
    }
}
